  1	import * as React from "react";
  2	
  3	import { K8sResourceCommon } from "@openshift-console/dynamic-plugin-sdk";
  4	import { Button, Grid } from "@patternfly/react-core";
  5	import { PlusCircleIcon } from "@patternfly/react-icons";
  6	
  7	import { AnnotationsModalRow } from "./AnnotationsModalRow";
  8	
  9	import "./AnnotationsModal.css";
 10	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 11	import TabModal from "../TabModal/TabModal";
 12	import { uniqBy, find, clone } from "lodash";
 13	
 14	type Annotations = { [key: string]: string };
 15	
 16	type AnnotationRowData = {
 17	  key: string;
 18	  value: string;
 19	  id: number;
 20	};
 21	
 22	type AnnotationsArray = AnnotationRowData[];
 23	
 24	const getAnnotationRowData = (
 25	  key: string,
 26	  value: string
 27	): AnnotationRowData => ({
 28	  key,
 29	  value,
 30	  id: Math.random(),
 31	});
 32	
 33	const toAnnotationArray = (
 34	  annotationsObject: Annotations | undefined
 35	): AnnotationsArray => {
 36	  if (!annotationsObject) {
 37	    return [getAnnotationRowData("", "")];
 38	  }
 39	  return Object.entries(annotationsObject).map(([key, value]) =>
 40	    getAnnotationRowData(key, value)
 41	  );
 42	};
 43	
 44	const toAnnotations = (annotationsArray: AnnotationsArray): Annotations => {
 45	  const ret: Annotations = {};
 46	  for (const { key, value } of annotationsArray) {
 47	    if (key === "") {
 48	      continue;
 49	    }
 50	    ret[key] = value;
 51	  }
 52	  return ret;
 53	};
 54	
 55	export const AnnotationsModal: React.FC<{
 56	  obj: K8sResourceCommon;
 57	  onSubmit: (annotations: {
 58	    [key: string]: string;
 59	  }) => Promise<void | K8sResourceCommon>;
 60	  isOpen: boolean;
 61	  onClose: () => void;
 62	}> = ({ obj, isOpen, onSubmit, onClose }) => {
 63	  const { t } = useNodeHealthCheckTranslation();
 64	
 65	  const [annotations, setAnnotations] = React.useState<AnnotationsArray>([]);
 66	
 67	  const onAnnotationAdd = () => {
 68	    setAnnotations([...annotations, getAnnotationRowData("", "")]);
 69	  };
 70	
 71	  const onAnnotationsSubmit = () => {
 72	    if (uniqBy(annotations, ({ key }) => key).length !== annotations.length) {
 73	      return Promise.reject({ message: t("Duplicate keys found") });
 74	    }
 75	
 76	    const updatedAnnotations = toAnnotations(annotations);
 77	
 78	    return onSubmit(updatedAnnotations);
 79	  };
 80	
 81	  const onRowChange = (id, key, value) => {
 82	    const rowData = find(annotations, { id });
 83	    if (!rowData) {
 84	      console.error(`Failed to find annotation id of  ${key}: ${value}`);
 85	      return;
 86	    }
 87	    rowData.key = key;
 88	    rowData.value = value;
 89	    setAnnotations(clone(annotations));
 90	  };
 91	
 92	  const onDelete = (deleteId) => {
 93	    setAnnotations(annotations.filter(({ id }) => deleteId !== id));
 94	  };
 95	
 96	  // reset annotations when modal is closed
 97	  React.useEffect(() => {
 98	    setAnnotations(toAnnotationArray(obj.metadata?.annotations));
 99	    // eslint-disable-next-line react-hooks/exhaustive-deps
100	  }, [isOpen]);
101	
102	  return (
103	    <TabModal<K8sResourceCommon>
104	      obj={obj}
105	      headerText={t("Edit annotations")}
106	      onSubmit={onAnnotationsSubmit}
107	      isOpen={isOpen}
108	      onClose={onClose}
109	      submitBtnType="submit"
110	    >
111	      <Grid hasGutter>
112	        {annotations.map((curAnnotation) => (
113	          <AnnotationsModalRow
114	            key={curAnnotation.id}
115	            annotation={curAnnotation}
116	            onChange={({ key, value }) =>
117	              onRowChange(curAnnotation.id, key, value)
118	            }
119	            onDelete={() => onDelete(curAnnotation.id)}
120	          />
121	        ))}
122	        <div className="co-toolbar__group co-toolbar__group--left">
123	          <Button
124	            className="pf-m-link--align-left"
125	            variant="link"
126	            onClick={onAnnotationAdd}
127	            icon={<PlusCircleIcon />}
128	          >
129	            {t("Add more")}
130	          </Button>
131	        </div>
132	      </Grid>
133	    </TabModal>
134	  );
135	};

